const data = $input.first().json;

function findValue(part) {
  const entry = Object.entries(data).find(([key]) =>
    key.toLocaleLowerCase("tr-TR").includes(part.toLocaleLowerCase("tr-TR"))
  );
  return entry ? entry[1] : "";
}

const adSoyad = findValue("adınız ve soyadınız");
const email = String(findValue("email adresiniz")).trim().toLowerCase();
const telefon = findValue("telefon numaranız");

const yas18Raw = findValue("18 yaşından büyük");
const aiOnayRaw = findValue("başvuru bilgilerimin");

const pozisyon = findValue("hangi pozisyona başvuruyorsunuz");
const deneyimYili = Number(findValue("kaç yıllık deneyiminiz")) || 0;
const egitim = findValue("eğitim bilginizi");
const yabanciDil = findValue("yabancı dil");
const teknikBeceriler = findValue("teknik becerilerinizi");
const kendiniTanit = findValue("kendinizi kısaca");
const uygunlukCevabi = findValue("neden bu pozisyona uygun");
const beklenenMaas = findValue("beklenen maaş");
const calismaTercihi = findValue("çalışma tercihiniz");
const profilLinki = findValue("portfolio linkinizi");
const cvLinki = findValue("cv dosyanızın erişilebilir");

const yas18Text = String(yas18Raw).trim().toLocaleLowerCase("tr-TR");
const aiOnayText = String(aiOnayRaw).trim().toLocaleLowerCase("tr-TR");

const yas18 =
  yas18Raw === true ||
  yas18Text === "evet" ||
  yas18Text === "yes" ||
  yas18Text === "true";

const aiOnayi =
  aiOnayRaw === true ||
  aiOnayText === "kabul ediyorum" ||
  aiOnayText === "i accept" ||
  aiOnayText === "accept" ||
  aiOnayText === "accepted" ||
  aiOnayText === "true";

const emailGecerli = email.includes("@") && email.includes(".");

const zorunluAlanlarDolu = Boolean(
  adSoyad &&
  emailGecerli &&
  pozisyon &&
  teknikBeceriler &&
  kendiniTanit &&
  uygunlukCevabi &&
  cvLinki
);

const gecerliBasvuru = Boolean(yas18 && aiOnayi && zorunluAlanlarDolu);

return [
  {
    json: {
      ad_soyad: adSoyad,
      email,
      telefon,
      yas18,
      ai_onayi: aiOnayi,
      pozisyon,
      deneyim_yili: deneyimYili,
      egitim,
      yabanci_dil: yabanciDil,
      teknik_beceriler: teknikBeceriler,
      kendini_tanit: kendiniTanit,
      uygunluk_cevabi: uygunlukCevabi,
      beklenen_maas: beklenenMaas,
      calisma_tercihi: calismaTercihi,
      profil_linki: profilLinki,
      cv_linki: cvLinki,
      basvuru_adi: `${adSoyad} - ${pozisyon}`,
      gecerli_basvuru: gecerliBasvuru,
      gecersiz_basvuru_nedeni: !yas18
        ? "18+ uygunluk sağlanmadı"
        : !aiOnayi
        ? "AI bilgilendirme onayı verilmedi"
        : !zorunluAlanlarDolu
        ? "Zorunlu alanlar eksik"
        : "",
      raw_typeform_json: JSON.stringify(data)
    }
  }
];

const input = $input.first().json;

const raw =
  input.output?.[0]?.content?.[0]?.text ||
  input.content?.[0]?.text ||
  input.message?.content ||
  input.message ||
  input.text ||
  input.response ||
  input.content ||
  "";

let cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    ai_puani: 0,
    ai_guven_skoru: 0,
    karar: "INSAN_KONTROLU",
    karar_gerekcesi: "AI çıktısı JSON formatında parse edilemedi. İnsan kontrolü önerildi.",
    guclu_yonler: [],
    zayif_yonler: ["AI çıktısı teknik olarak işlenemedi."],
    risk_notu: "JSON parse hatası: " + error.message,
    pozisyona_ozel_degerlendirme: "",
    insan_kontrol_notu: "AI yanıtı işlenemediği için başvuru insan kontrolüne alınmalıdır.",
    bias_kontrol_notu: "Parse hatası nedeniyle bias kontrolü yapılamadı.",
    mulakat_sorulari: [],
    kisa_ozet: "AI analizi teknik hata nedeniyle tamamlanamadı."
  };
}

function arrToText(value, fallback) {
  if (Array.isArray(value)) {
    const cleanedArray = value.filter(Boolean);
    return cleanedArray.length ? cleanedArray.join("\n") : fallback;
  }
  if (value === null || value === undefined || String(value).trim() === "") {
    return fallback;
  }
  return String(value);
}

const kararlar = ["KESIN_RED", "INSAN_KONTROLU", "MULAKAT_ONER"];
const karar = kararlar.includes(parsed.karar) ? parsed.karar : "INSAN_KONTROLU";

const basvuruDurumuMap = {
  KESIN_RED: "AI Reddetti",
  INSAN_KONTROLU: "İnsan Kontrolü Gerekli",
  MULAKAT_ONER: "Mülakat Önerildi"
};

return [
  {
    json: {
      ai_puani: Number(parsed.ai_puani) || 0,
      ai_guven_skoru: Number(parsed.ai_guven_skoru) || 0,
      karar,
      basvuru_durumu: basvuruDurumuMap[karar] || "İnsan Kontrolü Gerekli",

      karar_gerekcesi:
        parsed.karar_gerekcesi ||
        "Karar gerekçesi üretilemedi. İnsan kontrolü önerilir.",

      guclu_yonler: arrToText(
        parsed.guclu_yonler,
        "Güçlü yön bilgisi üretilemedi."
      ),

      zayif_yonler: arrToText(
        parsed.zayif_yonler,
        "Belirgin zayıf yön tespit edilmedi."
      ),

      risk_notu:
        parsed.risk_notu ||
        "Belirgin risk tespit edilmedi.",

      pozisyona_ozel_degerlendirme:
        parsed.pozisyona_ozel_degerlendirme ||
        "Pozisyona özel değerlendirme üretilemedi.",

      insan_kontrol_notu:
        parsed.insan_kontrol_notu ||
        "AI önerisi insan kaynakları uzmanı tarafından son kez kontrol edilmelidir.",

      bias_kontrol_notu:
        parsed.bias_kontrol_notu ||
        "Değerlendirme teknik beceri ve pozisyon uygunluğu üzerinden yapılmıştır; hassas özellikler dikkate alınmamıştır.",

      mulakat_sorulari: arrToText(
        parsed.mulakat_sorulari,
        "Mülakat sorusu üretilemedi."
      ),

      kisa_ozet:
        parsed.kisa_ozet ||
        "Kısa özet üretilemedi.",

      raw_json: JSON.stringify(parsed)
    }
  }
];

